     * @param string|null $repo The repository to tag in. For example, `someuser/someimage`.
     * @param string|null $tag The name of the new tag.
     *
     * @return void Response from the API call
     *
     * @throws ApiException Thrown if API call fails
     */
    public function imageTag(string $name, ?string $repo = null, ?string $tag = null): void
    {
        $_reqBuilder = $this->requestBuilder(RequestMethod::POST, '/images/{name}/tag')
            ->parameters(
                TemplateParam::init('name', $name),
                QueryParam::init('repo', $repo),
                QueryParam::init('tag', $tag)
            );

        $_resHandler = $this->responseHandler()
            ->throwErrorOn('400', ErrorType::init('Bad parameter', ImagesTag400ErrorException::class))
            ->throwErrorOn('404', ErrorType::init('No such image', ImagesTag404ErrorException::class))
            ->throwErrorOn('409', ErrorType::init('Conflict', ImagesTag409ErrorException::class))
            ->throwErrorOn('500', ErrorType::init('Server error', ImagesTag500ErrorException::class));

        $this->execute($_reqBuilder, $_resHandler);
    }
}
